const input = $json.body ?? $json;
const notification = input.notification ?? {};
const metricsIn = input.metrics ?? {};
const incidents = Array.isArray(input.incidents) ? input.incidents : [];

const metrics = {
  contracts_evaluated: Number(metricsIn.contracts_evaluated ?? 0),
  ads_evaluated: Number(metricsIn.ads_evaluated ?? 0),
  paused_success_count: Number(metricsIn.paused_success_count ?? 0),
  paused_error_count: Number(metricsIn.paused_error_count ?? 0),
  expired_unpaused_count: Number(metricsIn.expired_unpaused_count ?? 0),
  preventive_48h_count: Number(metricsIn.preventive_48h_count ?? 0),
  duration_ms: Number(metricsIn.duration_ms ?? 0)
};

const executionStatus = String(input.execution_status ?? input.status ?? 'unknown').toLowerCase();
const isCritical = metrics.expired_unpaused_count > 0;

let severity = 'INFO';
if (isCritical) {
  severity = 'CRITICAL';
} else if (executionStatus !== 'success' || metrics.paused_error_count > 0 || incidents.length > 0) {
  severity = 'WARN';
}

const correlationId = String(input.correlation_id ?? input.execution_id ?? `ops-${Date.now()}`);
const timezone = input.timezone ?? 'America/Argentina/Buenos_Aires';

return [{
  json: {
    ...input,
    correlation_id: correlationId,
    execution_status: executionStatus,
    timezone,
    incidents,
    metrics,
    notification,
    derived: {
      severity,
      is_critical: isCritical,
      execution_mode: String(input.execution_mode ?? 'scheduled').toLowerCase(),
      executed_at: input.executed_at ?? new Date().toISOString()
    }
  }
}];

return [{
  json: {
    event: 'ops_notification_channel_error',
    channel: String($json.notification?.channel ?? 'unknown').toLowerCase(),
    severity: $json.derived?.severity ?? 'WARN',
    correlation_id: $json.correlation_id ?? null,
    execution_id: $json.execution_id ?? null,
    message: 'Fallo de envío de notificación. MVP sin fallback automático entre canales.',
    timestamp: new Date().toISOString()
  }
}];

return [{
  json: {
    event: 'ops_notification_sent',
    channel: 'slack',
    severity: $json.derived?.severity ?? 'INFO',
    correlation_id: $json.correlation_id ?? null,
    execution_id: $json.execution_id ?? null,
    message: 'Notificación enviada por Slack.',
    timestamp: new Date().toISOString()
  }
}];

return [{
  json: {
    event: 'ops_notification_sent',
    channel: 'telegram',
    severity: $json.derived?.severity ?? 'INFO',
    correlation_id: $json.correlation_id ?? null,
    execution_id: $json.execution_id ?? null,
    message: 'Notificación enviada por Telegram.',
    timestamp: new Date().toISOString()
  }
}];

return [{
  json: {
    event: 'ops_notification_channel_unsupported',
    channel: String($json.notification?.channel ?? 'undefined').toLowerCase(),
    severity: 'ERROR',
    correlation_id: $json.correlation_id ?? null,
    execution_id: $json.execution_id ?? null,
    message: 'Canal no soportado. Solo Slack o Telegram en MVP.',
    timestamp: new Date().toISOString()
  }
}];
